-- Simplified topic descriptions: replace scholarly/theological jargon with everyday language

UPDATE recommended_topics_translations
SET description = 'यीशु मसीह की पहचान के बारे में बाइबिल की सच्चाई का पता लगाएं - पूर्णतः परमेश्वर और पूर्णतः मनुष्य, शाश्वत परमेश्वर का पुत्र जो हमारे उद्धार को पूरा करने के लिए देह बना। जानें कि बाइबल यीशु को प्रतिज्ञा किए गए मसीहा, एकमात्र उद्धारकर्ता के रूप में कैसे प्रकट करता है जो पापियों के लिए मरा और मृतकों में से जी उठा, और सारी सृष्टि पर सर्वोच्च प्रभु। समझें कि यीशु वास्तव में कौन हैं, यह पहचानना सच्चे मसीही विश्वास की नींव क्यों बनता है और उनका व्यक्तित्व और कार्य सुसमाचार संदेश के केंद्र में कैसे हैं। यह अध्ययन विश्वासियों को मसीह के देवत्व, मानवता और छुटकारे के मिशन की ऐतिहासिक, सदियों से मानी जाने वाली समझ में स्थापित करता है।'
WHERE topic_id = '111e8400-e29b-41d4-a716-446655440001' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'बाइबल की महत्ता की खोज करें - परमेश्वर का लिखित, बिना किसी गलती के वचन - मसीही जीवन में। समझें कि बाइबल मानव ज्ञान या धार्मिक विचारों का संग्रह नहीं है, बल्कि परमेश्वर के आत्मा द्वारा लिखाया हुआ प्रकाशन है (2 तीमुथियुस 3:16)। जानें कि बाइबल विश्वासियों को शिक्षित, सुधारता, मार्गदर्शन करता और परमेश्वर के चरित्र और इरादे को प्रकट करता है। बाइबल पढ़ना भोजन के समान है - आप इसके बिना आत्मिक रूप से भूखे रहेंगे। यह अध्ययन आपको नियमित, जानबूझकर बाइबल अध्ययन के लिए लैस करता है, आपके मन को नवीनीकृत करने, आपको सत्य में स्थापित करने, और आपको मसीह की समानता में बदलने के लिए।'
WHERE topic_id = '111e8400-e29b-41d4-a716-446655440004' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'प्रार्थना को परमेश्वर के साथ संवाद के रूप में, शक्ति के स्रोत के रूप में, और सच्ची आराधना के कार्य के रूप में खोजें। समझें कि प्रार्थना एक धार्मिक अनुष्ठान नहीं है, बल्कि पवित्र परमेश्वर के साथ विनम्र बातचीत है जो मसीह के माध्यम से उसकी उपस्थिति में पहुंच प्रदान करता है। सीखें कि प्रार्थना में कैसे निडर होकर आएं (इब्रानियों 4:16), अपने पापों को स्वीकार करें, अपनी आवश्यकताओं को व्यक्त करें, दूसरों के लिए बीच में खड़े होकर प्रार्थना करें, और परमेश्वर की महिमा करें। प्रभावी प्रार्थना की शक्ति उत्कृष्ट शब्दों में नहीं है, बल्कि विश्वास से भरे हृदय और परमेश्वर की प्रभुता में विश्वास में है। यह अध्ययन आपको गहरी, उद्देश्यपूर्ण प्रार्थना जीवन विकसित करने में मदद करता है जो परमेश्वर का सम्मान करता है।'
WHERE topic_id = '111e8400-e29b-41d4-a716-446655440005' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'केवल इच्छाशक्ति से नहीं, बल्कि पवित्र आत्मा की शक्ति, बाइबल और परमेश्वर की प्रतिज्ञाओं के माध्यम से पाप का विरोध कैसे करें।'
WHERE topic_id = '222e8400-e29b-41d4-a716-446655440002' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'स्थानीय कलीसिया के भीतर मसीही संगति के जरूरी महत्व को खोजें। जानें कि बाइबल विश्वासियों को एक साथ इकट्ठा होने से मना करने की आज्ञा क्यों देता है (इब्रानियों 10:25), क्योंकि आत्मिक विकास, जवाबदेही, प्रोत्साहन और झूठी शिक्षा से सुरक्षा के लिए अन्य मसीहियों के साथ प्रतिबद्ध रिश्तों की आवश्यकता होती है। संगति को आकस्मिक सामाजिकता से अधिक के रूप में समझें - यह मसीह में साझा जीवन है, जो पारस्परिक प्रेम, सत्य-बोलने, स्वीकारोक्ति, प्रार्थना और आत्मिक वरदानों के प्रयोग से विशेषता है। यह अध्ययन सांस्कृतिक व्यक्तिवाद को चुनौती देता है और विश्वासियों को मसीह के शरीर के भीतर गहरे, जानबूझकर रिश्तों के लिए बुलाता है, जहां लोहा लोहे को तेज करता है (नीतिवचन 27:17) और सुसमाचार दृश्य समुदाय में जीया जाता है।'
WHERE topic_id = '333e8400-e29b-41d4-a716-446655440002' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'कलीसिया के भीतर एकता का पीछा करने के बाइबल के आह्वान को खोजें, सुसमाचार की सच्चाई में आधारित और पवित्र आत्मा द्वारा सशक्त। जानें कि मसीही एकता केवल सहमति या सहिष्णुता नहीं है, बल्कि मसीह में साझा विश्वास, बाइबल के प्रति समर्पण और पारस्परिक प्रेम में निहित आत्मिक एकता है (यूहन्ना 17:20-23)। समझें कि सही बातें मानते हुए एकता कैसे बनाए रखें, विभाजनकारी कानूनीवाद और समझौता करने वाले बहुलवाद दोनों से बचें। यह अध्ययन सिखाता है कि प्रेम में एक दूसरे के साथ कैसे सहन करें, बाइबल के अनुसार संघर्षों को हल करें, और देखने वाली दुनिया को विश्वासियों के बीच दृश्य प्रेम और सद्भाव के माध्यम से सुसमाचार की प्रामाणिकता प्रदर्शित करें, सब परमेश्वर की महिमा और कलीसिया की गवाही के लिए।'
WHERE topic_id = '333e8400-e29b-41d4-a716-446655440004' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'यीशु की अपने शिष्यों को अंतिम आज्ञा को खोजें: "इसलिए जाओ, सभी राष्ट्रों के शिष्य बनाओ, उन्हें बपतिस्मा दो और उन्हें वह सब कुछ मानना सिखाओ जो मैंने तुम्हें आज्ञा दी है" (मत्ती 28:19-20)। जानें कि महान आज्ञा केवल मिशनरियों या पादरियों के लिए नहीं है, बल्कि हर विश्वासी के लिए है जो हर जनजाति, भाषा और राष्ट्र से लोगों को इकट्ठा करने की परमेश्वर की योजना में भागीदार हैं। आवश्यक तत्वों को समझें: सुसमाचार के साथ जाना, शिष्य बनाना (केवल धर्म बदलवाना नहीं), परमेश्वर के लोगों से संबंधित होने के संकेत के रूप में बपतिस्मा देना, और मसीह की आज्ञाकारिता सिखाना। यह अध्ययन मसीह के अधिकार में विश्वास में आधारित, आत्मा की उपस्थिति से सशक्त, और परमेश्वर की महिमा और खोए हुओं के उद्धार के लिए प्रेम से प्रेरित वफादार सुसमाचार प्रचार और शिष्यत्व को प्रेरित करता है।'
WHERE topic_id = '444e8400-e29b-41d4-a716-446655440004' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'आत्मिक मार्गदर्शन के बाइबल मॉडल को सीखें, जहां परिपक्व विश्वासी युवा मसीहियों में शिक्षण, ईश्वरीयता का मॉडलिंग, और प्रोत्साहन और जवाबदेही प्रदान करके निवेश करते हैं (2 तीमुथियुस 2:2)। समझें कि मार्गदर्शन श्रेष्ठता या पूर्णता के बारे में नहीं है, बल्कि विनम्रता से प्राप्त अनुग्रह को साझा करना, दूसरों को मसीह की ओर इशारा करना, और उन्हें विश्वास और आज्ञाकारिता में बढ़ने में मदद करना है। बाइबल अध्ययन, प्रार्थना, ईमानदार बातचीत और जानबूझकर शिष्यत्व संबंधों के माध्यम से दूसरों को सलाह देने के व्यावहारिक तरीकों की खोज करें। यह अध्ययन इस बात पर जोर देता है कि मार्गदर्शन एक विशेषाधिकार और जिम्मेदारी दोनों है, जो आपके अपने जीवन में परमेश्वर के कार्य के प्रवाह से बहती है और परमेश्वर की महिमा के लिए पीढ़ियों में वफादार शिष्यों के गुणन में योगदान देती है।'
WHERE topic_id = '444e8400-e29b-41d4-a716-446655440005' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'परमेश्वर के साथ दैनिक भक्ति समय के आवश्यक अभ्यास की खोज करें - बाइबल पढ़ने, प्रार्थना करने और प्रभु के साथ संगति के लिए नियमित क्षण निर्धारित करना। जानें कि दैनिक भक्ति परमेश्वर का पक्ष पाने के लिए धार्मिक नियमों के अनुष्ठान नहीं हैं, बल्कि अनुग्रह के महत्वपूर्ण साधन हैं जो आपकी आत्मा को पोषित करते हैं, परमेश्वर के साथ आपके रिश्ते को गहरा करते हैं, और मसीह के साथ आपकी चाल को बनाए रखते हैं। समझें कि परमेश्वर के वचन और प्रार्थना में लगातार समय विश्वास को कैसे मजबूत करता है, मार्गदर्शन प्रदान करता है, आपके मन को नवीनीकृत करता है, और आपको आत्मिक लड़ाइयों के लिए सुसज्जित करता है (इफिसियों 6:10-18)। यह अध्ययन भक्ति की स्थायी लय स्थापित करने के लिए व्यावहारिक मार्गदर्शन प्रदान करता है, इस बात पर जोर देते हुए कि लक्ष्य केवल धार्मिक कर्तव्य नहीं है बल्कि परमेश्वर में आनंद लेना, पवित्रता में बढ़ना और रोज मसीह में बने रहना है।'
WHERE topic_id = '555e8400-e29b-41d4-a716-446655440001' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'परमेश्वर के वचन पर मनन के बाइबल अभ्यास को सीखें - पूर्वी आध्यात्मिक प्रथाओं की तरह मन को खाली करना नहीं, बल्कि परमेश्वर के सत्य को समझने, आंतरिक बनाने और लागू करने के लिए बाइबल पर केंद्रित, प्रार्थनापूर्ण चिंतन। खोजें कि मनन में बाइबल को धीरे-धीरे पढ़ना, इसके अर्थ पर विचार करना, इसके माध्यम से प्रार्थना करना और पवित्र आत्मा को आपके हृदय और मन को प्रबुद्ध और परिवर्तित करने की अनुमति देना शामिल है (भजन 1:2-3)। समझें कि परमेश्वर के वचन पर मनन विश्वास को कैसे मजबूत करता है, सोच को नवीनीकृत करता है, पाप को उजागर करता है, और आपको मसीह की छवि के अनुरूप बनाता है। यह अध्ययन आपको सतही बाइबल पढ़ने से बाइबल के साथ गहरी सगाई की ओर ले जाने के लिए सुसज्जित करता है, जहां परमेश्वर का सत्य आपकी आत्मा में जड़ें लेता है और स्थायी आत्मिक फल और मसीह-समान चरित्र उत्पन्न करता है।'
WHERE topic_id = '555e8400-e29b-41d4-a716-446655440004' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'आत्मिक डायरी लेखन के अभ्यास को परमेश्वर की वफादारी को रिकॉर्ड करने, आपके आत्मिक विकास को ट्रैक करने और लिखित चिंतन के माध्यम से मसीह के साथ अपनी चाल को संसाधित करने के साधन के रूप में खोजें। जानें कि डायरी में प्रार्थनाओं को रिकॉर्ड करना, प्रार्थनाओं के उत्तर, बाइबल से अंतर्दृष्टि, पाप की स्वीकारोक्ति, कृतज्ञता की अभिव्यक्ति और आपके जीवन में परमेश्वर के प्रावधान पर प्रतिबिंब शामिल हो सकता है। समझें कि डायरी साहित्यिक कौशल या प्रदर्शन के बारे में नहीं है, बल्कि परमेश्वर के साथ ईमानदार संगति और उसके सामने जानबूझकर आत्म-परीक्षा के बारे में है। यह अध्ययन दिखाता है कि कैसे डायरी परमेश्वर के कार्य की अधिक जागरूकता, गहरी कृतज्ञता और स्पष्ट आत्मिक समझ को बढ़ावा देती है, परमेश्वर के अनुग्रह की व्यक्तिगत गवाही और विश्वास में लगातार बढ़ने तथा उसकी भलाई को याद रखने के उपकरण के रूप में सेवा करती है।'
WHERE topic_id = '555e8400-e29b-41d4-a716-446655440005' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'बाइबल की इस सच्चाई को खोजें कि केवल एक सच्चा परमेश्वर है, शाश्वत, स्व-अस्तित्व और सारी सृष्टि पर सर्वोच्च (व्यवस्थाविवरण 6:4; यशायाह 44:6)। जानें कि बाइबल लगातार परमेश्वर को आराधना के योग्य एकमात्र देवता के रूप में कैसे प्रकट करता है, आसपास की संस्कृतियों में अनेक देवताओं में विश्वास और आधुनिक बहुलवादी दावों के विपरीत। समझें कि मसीही एकेश्वरवाद त्रिएक है: तीन व्यक्तियों में एक परमेश्वर - पिता, पुत्र और पवित्र आत्मा - विशिष्ट लेकिन सार में एकजुट। यह अध्ययन आपको झूठे धर्मों, मूर्तिपूजा और सापेक्षवाद के खिलाफ बाइबल के परमेश्वर की विशिष्टता की रक्षा करने के लिए सुसज्जित करता है, आपके विश्वास को बाइबल की स्पष्ट गवाही में आधारित करता है और आपको परमेश्वर की एकवचन महिमा की सच्चाई को स्पष्ट करने के लिए तैयार करता है।'
WHERE topic_id = '666e8400-e29b-41d4-a716-446655440001' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'खोजें कि यीशु मसीह उद्धार का एकमात्र मार्ग क्यों है, जैसा कि उन्होंने स्वयं घोषित किया: "मैं मार्ग और सत्य और जीवन हूं। कोई भी पिता के पास नहीं आता सिवाय मेरे द्वारा" (यूहन्ना 14:6)। जानें कि यीशु की अद्वितीय पहचान परमेश्वर के अवतार के रूप में, उनका निष्पाप जीवन, हमारी जगह मरने की मृत्यु और शारीरिक पुनरुत्थान उन्हें परमेश्वर और मानवता के बीच एकमात्र जोड़ने वाले के रूप में कैसे स्थापित करता है (1 तीमुथियुस 2:5)। समझें कि धार्मिक बहुलवाद - यह विचार कि सभी मार्ग परमेश्वर की ओर ले जाते हैं - बाइबल और सुसमाचार दोनों का खंडन क्यों करता है। यह अध्ययन आपको बाइबल सत्य में आधारित और खोए हुओं के लिए प्रेम और परमेश्वर की महिमा के लिए उत्साह से प्रेरित, बहुलवादी दुनिया में कृपापूर्वक लेकिन दृढ़ता से मसीह के अनन्य दावों की घोषणा करने के लिए सुसज्जित करता है।'
WHERE topic_id = '666e8400-e29b-41d4-a716-446655440002' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'परमेश्वर की प्रेरणा से लिखी गई, बिना किसी गलती के परमेश्वर के वचन के रूप में बाइबल की विश्वसनीयता और भरोसेमंदता के लिए ठोस साक्ष्य की जांच करें। जानें कि कैसे पुरानी हस्तलिखित प्रतियों के प्रमाण, पुरानी खुदाइयों से मिले प्रमाण, पूर्ण भविष्यवाणी, आपस में मेल और पवित्र आत्मा की गवाही सभी बाइबल के परमेश्वर की ओर से होने और उसके अधिकार की पुष्टि करती हैं। समझें कि बाइबल की विश्वसनीयता मानव राय या विद्वानों की सहमति पर आधारित नहीं है, बल्कि सत्य के परमेश्वर के चरित्र पर जो झूठ नहीं बोल सकता। यह अध्ययन आपको संदेह करने वालों की आपत्तियों का उत्तर देने, परमेश्वर के वचन में अपने विश्वास को मजबूत करने, और सिद्धांत और जीवन के सभी मामलों में विश्वास और अभ्यास के लिए अंतिम अधिकार के रूप में बाइबल की नींव पर दृढ़ रहने के लिए सुसज्जित करता है।'
WHERE topic_id = '666e8400-e29b-41d4-a716-446655440003' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'अन्य धर्मों के लोगों के साथ सम्मानपूर्वक और बाइबल के अनुसार कैसे जुड़ें, सत्य और अनुग्रह दोनों के साथ ईसाई धर्म के बारे में उनके प्रश्नों का उत्तर दें (1 पतरस 3:15-16)। हिंदू धर्म, इस्लाम, बौद्ध धर्म और अन्य धर्मों से सामान्य आपत्तियों को कैसे समझें और बाइबल में निहित स्पष्ट सुसमाचार-केंद्रित उत्तरों के साथ जवाब दें। बाइबल की सच्चाई की रक्षा और मसीह-समान प्रेम और विनम्रता प्रदर्शित करने के बीच संतुलन को समझें। यह अध्ययन आपको सुसमाचार की विशिष्टता को स्पष्ट करने, झूठे धर्मों की अपर्याप्तता को उजागर करने और दूसरों को एकमात्र उद्धारकर्ता यीशु की ओर इशारा करने के लिए तैयार करता है - सभी कोमलता, सम्मान और उन लोगों की आत्माओं के लिए वास्तविक चिंता की मुद्रा बनाए रखते हुए जो अभी तक मसीह को नहीं जानते।'
WHERE topic_id = '666e8400-e29b-41d4-a716-446655440004' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'मसीह के लिए उत्पीड़न और विरोध सहने के लिए बाइबल प्रोत्साहन और व्यावहारिक ज्ञान की खोज करें। जानें कि कैसे यीशु ने वादा किया कि उनके अनुयायियों को क्लेश का सामना करना पड़ेगा (यूहन्ना 16:33), फिर भी उन्होंने अपनी उपस्थिति, शक्ति और अंतिम विजय का भी वादा किया। समझें कि उत्पीड़न परमेश्वर की अनुपस्थिति का संकेत नहीं है बल्कि अक्सर सच्चे शिष्यत्व का चिह्न है (2 तीमुथियुस 3:12)। यह अध्ययन सिखाता है कि पीड़ा के माध्यम से विश्वास में कैसे दृढ़ रहें, समझौता करने या मसीह को नकारने के प्रलोभन का विरोध करें, और उसकी पीड़ाओं में साझा करने में आनंद पाएं (1 पतरस 4:12-14)। बाइबल की प्रतिज्ञाओं में आधारित, पवित्र आत्मा द्वारा निर्वाह, और मसीह के प्रति वफादार रहने वालों की प्रतीक्षा करने वाले शाश्वत पुरस्कार में आश्वस्त आशा के साथ कठिनाई सहने के लिए सुसज्जित हों।'
WHERE topic_id = '666e8400-e29b-41d4-a716-446655440005' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'विवाह के लिए बाइबल दृष्टि को एक पुरुष और एक महिला के बीच पवित्र, आजीवन प्रतिबद्धता के रूप में खोजें, जिसे मसीह के अपनी कलीसिया के साथ संबंध को प्रतिबिंबित करने के लिए परमेश्वर द्वारा डिज़ाइन किया गया है (इफिसियों 5:22-33)। जानें कि कैसे मसीह-केंद्रित विवाह परमेश्वर के वचन के प्रति पारस्परिक समर्पण, मसीह के बाद बलिदान प्रेम और परमेश्वर के बनाए गए क्रम का सम्मान करने वाली भूमिकाओं पर निर्मित है। समझें कि सुसमाचार विवाह को स्व-केंद्रित साझेदारी से निःस्वार्थ, विश्वासयोग्य प्रतिबद्धता में कैसे बदल देता है। यह अध्ययन संचार, संघर्ष समाधान, अंतरंगता और आत्मिक नेतृत्व जैसे व्यावहारिक क्षेत्रों को संबोधित करता है, सभी बाइबल में आधारित। खोजें कि विवाह अंततः व्यक्तिगत खुशी के बारे में नहीं है बल्कि परमेश्वर की महिमा करने, सुसमाचार प्रदर्शित करने और मसीह और उसकी कलीसिया की सेवा में एक साथ भागीदारी करने के बारे में है।'
WHERE topic_id = '777e8400-e29b-41d4-a716-446655440001' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'मसीह-केंद्रित मित्रता बनाने के लिए बाइबल सिद्धांतों की खोज करें जो आत्मिक विकास, जवाबदेही और पारस्परिक निर्माण को प्रोत्साहित करें। जानें कि कैसे बाइबल अधर्मी मित्रता के खिलाफ चेतावनी देता है जो समझौता (1 कुरिन्थियों 15:33) की ओर ले जाती है जबकि परमेश्वर के प्रेम और पवित्रता की खोज में निहित मित्रता की सराहना करता है (नीतिवचन 27:17)। स्वस्थ मसीही मित्रता के गुणों को समझें: वफादारी, ईमानदारी, प्रोत्साहन, जवाबदेही और मसीह के प्रति साझा प्रतिबद्धता। यह अध्ययन बुद्धिमानी से दोस्तों को चुनने, ईश्वरीय सीमाओं को बनाए रखने और उन रिश्तों में निवेश करने के लिए व्यावहारिक मार्गदर्शन प्रदान करता है जो एक दूसरे को यीशु की ओर इशारा करते हैं। जानें कि कैसे सच्ची मित्रता मसीह के प्रेम को दर्शाती है और मसीही जीवन में अनुग्रह के साधन के रूप में कार्य करती है।'
WHERE topic_id = '777e8400-e29b-41d4-a716-446655440004' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'राष्ट्रों के लिए प्रार्थना करने के बाइबल आह्वान की खोज करें, हर जनजाति, भाषा और राष्ट्र से उपासकों को इकट्ठा करने के परमेश्वर के वैश्विक मिशन में भाग लेते हुए (प्रकाशितवाक्य 7:9)। जानें कि अप्राप्त लोगों, सताए गए विश्वासियों और सुसमाचार प्रगति के लिए दूसरों की ओर से की जाने वाली प्रार्थना परमेश्वर की योजना के साथ कैसे संरेखित होती है कि वह मसीह की घोषणा के माध्यम से दुनिया भर में पापियों को बचाए। समझें कि कैसे वफादार प्रार्थना मिशनरियों का समर्थन करती है, सुसमाचार के लिए दरवाजे खोलती है, और उन स्थानों में परमेश्वर के राज्य को आगे बढ़ाती है जहां यीशु का नाम अभी तक ज्ञात नहीं है। यह अध्ययन विश्वासियों को मिशन के लिए वैश्विक दृष्टि विकसित करने, विशिष्ट आवश्यकताओं के लिए रणनीतिक रूप से प्रार्थना करने और परमेश्वर पर भरोसा करने के लिए प्रेरित करता है कि वह अपनी महिमा और सुसमाचार के प्रसार के लिए राष्ट्रों के बीच अपने उद्देश्यों को पूरा करे।'
WHERE topic_id = '888e8400-e29b-41d4-a716-446655440005' AND language_code = 'hi';

UPDATE recommended_topics_translations
SET description = 'യേശുക്രിസ്തുവിന്റെ സ്വത്വത്തെക്കുറിച്ചുള്ള ബൈബിളിലെ സത്യം പര്യവേക്ഷണം ചെയ്യുക - പൂർണ്ണമായും ദൈവവും പൂർണ്ണമായും മനുഷ്യനും - നമ്മുടെ രക്ഷ നിവർത്തിക്കാൻ ജഡമായി മാറിയ ദൈവത്തിന്റെ നിത്യപുത്രൻ. വേദപുസ്തകം യേശുവിനെ വാഗ്ദത്ത മിശിഹായായി, പാപികൾക്കുവേണ്ടി മരിച്ച് മരിച്ചവരിൽനിന്ന് ഉയിർത്തെഴുന്നേറ്റ ഏക രക്ഷകനായി, സർവ്വ സൃഷ്ടികൾക്കും മേലുള്ള ഉന്നത കർത്താവായി എങ്ങനെ വെളിപ്പെടുത്തുന്നുവെന്ന് പഠിക്കുക. യേശു യഥാർത്ഥത്തിൽ ആരാണെന്ന് തിരിച്ചറിയുന്നത് എന്തുകൊണ്ട് യഥാർത്ഥ ക്രിസ്തീയ വിശ്വാസത്തിന്റെ അടിസ്ഥാനം രൂപീകരിക്കുന്നുവെന്നും അവന്റെ വ്യക്തിത്വവും പ്രവൃത്തിയും സുവിശേഷസന്ദേശത്തിന്റെ കേന്ദ്രബിന്ദുവാകുന്നതെങ്ങനെയെന്നും മനസ്സിലാക്കുക. ഈ പഠനം വിശ്വാസികളെ ക്രിസ്തുവിന്റെ ദൈവത്വത്തെയും മാനവികതയെയും വീണ്ടെടുപ്പ് ദൗത്യത്തെയും കുറിച്ചുള്ള ചരിത്രപരവും സഭ ആദ്യം മുതൽ വിശ്വസിച്ചുവന്നതുമായ ധാരണയിൽ സ്ഥാപിക്കുന്നു.'
WHERE topic_id = '111e8400-e29b-41d4-a716-446655440001' AND language_code = 'ml';

UPDATE recommended_topics_translations
SET description = 'വേദപുസ്തകത്തിന്റെ കേന്ദ്രസ്ഥാനം പര്യവേക്ഷണം ചെയ്യുക - ദൈവത്തിന്റെ എഴുതപ്പെട്ട, പിശകില്ലാത്ത വചനം - ക്രിസ്തീയ ജീവിതത്തിൽ. ബൈബിൾ മാനുഷിക ജ്ഞാനത്തിന്റെയോ മതപരമായ ചിന്തകളുടെയോ സമാഹാരമല്ല, മറിച്ച് ദൈവത്തിന്റെ ആത്മാവ് നൽകിയ വെളിപ്പാടാണെന്ന് (2 തിമൊഥെയൊസ് 3:16) മനസ്സിലാക്കുക. വേദപുസ്തകം വിശ്വാസികളെ ഉപദേശിക്കുകയും തിരുത്തുകയും നയിക്കുകയും ദൈവത്തിന്റെ സ്വഭാവവും ഉദ്ദേശ്യവും വെളിപ്പെടുത്തുകയും ചെയ്യുന്നുവെന്ന് പഠിക്കുക. ബൈബിൾ വായിക്കുന്നത് ഭക്ഷണം പോലെയാണ് - അതില്ലാതെ നിങ്ങൾ ആത്മീയമായി പട്ടിണി കിടക്കും. ഈ പഠനം നിങ്ങളുടെ മനസ്സ് പുതുക്കുന്നതിനും നിങ്ങളെ സത്യത്തിൽ സ്ഥാപിക്കുന്നതിനും നിങ്ങളെ ക്രിസ്തുവിന്റെ സാദൃശ്യത്തിലേക്ക് മാറ്റുന്നതിനും നിയമിത, ഉദ്ദേശിത ബൈബിൾ പഠനത്തിനായി നിങ്ങളെ സജ്ജമാക്കുന്നു.'
WHERE topic_id = '111e8400-e29b-41d4-a716-446655440004' AND language_code = 'ml';

UPDATE recommended_topics_translations
SET description = 'പ്രാർത്ഥനയെ ദൈവവുമായുള്ള ആശയവിനിമയമായും ശക്തിയുടെ ഉറവിടമായും യഥാർത്ഥ ആരാധനയുടെ പ്രവൃത്തിയായും പര്യവേക്ഷണം ചെയ്യുക. പ്രാർത്ഥന ഒരു മതപരമായ ആചാരമല്ല, മറിച്ച് ക്രിസ്തുവിലൂടെ തന്റെ സാന്നിധ്യത്തിലേക്ക് പ്രവേശനം നൽകുന്ന വിശുദ്ധ ദൈവവുമായുള്ള വിനീതമായ സംഭാഷണമാണെന്ന് മനസ്സിലാക്കുക. പ്രാർത്ഥനയിൽ എങ്ങനെ ധൈര്യത്തോടെ വരാമെന്നും (എബ്രായർ 4:16), നിങ്ങളുടെ പാപങ്ങൾ ഏറ്റുപറയാനും നിങ്ങളുടെ ആവശ്യങ്ങൾ പ്രകടിപ്പിക്കാനും മറ്റുള്ളവർക്കുവേണ്ടി ഇടനിലക്കാരനായി പ്രാർത്ഥിക്കാനും ദൈവത്തെ മഹത്വപ്പെടുത്താനും പഠിക്കുക. ഫലപ്രദമായ പ്രാർത്ഥനയുടെ ശക്തി മികച്ച വാക്കുകളിലല്ല, മറിച്ച് വിശ്വാസം നിറഞ്ഞ ഹൃദയത്തിലും ദൈവം സർവ്വത്തിന്റെയും കർത്താവ് എന്ന വിശ്വാസത്തിലുമാണ്. ഈ പഠനം ദൈവത്തെ ബഹുമാനിക്കുന്ന ആഴത്തിലുള്ള, ലക്ഷ്യബോധമുള്ള പ്രാർത്ഥനാ ജീവിതം വികസിപ്പിക്കാൻ നിങ്ങളെ സഹായിക്കുന്നു.'
WHERE topic_id = '111e8400-e29b-41d4-a716-446655440005' AND language_code = 'ml';

UPDATE recommended_topics_translations
SET description = 'ഒരേ ഒരു ദൈവം മാത്രമേ ഉള്ളൂ എന്ന ബൈബിളിലെ സത്യം പര്യവേക്ഷണം ചെയ്യുക - ഒരേയൊരു യഥാർത്ഥ ദൈവമേയുള്ളൂ, നിത്യൻ, സ്വയംനിലയുള്ളവൻ, എല്ലാ സൃഷ്ടികൾക്കും മേലുള്ള ഉടയോൻ (ആവർത്തനം 6:4; യെശയ്യാവ് 44:6). ചുറ്റുമുള്ള സംസ്കാരങ്ങളിലെ അനേകം ദൈവങ്ങളിലുള്ള വിശ്വാസത്തിനും ആധുനിക ബഹുസ്വരവാദ അവകാശവാദങ്ങൾക്കും വിപരീതമായി, ആരാധനയ്ക്ക് യോഗ്യനായ ഏക ദൈവമായി വേദപുസ്തകം ദൈവത്തെ എങ്ങനെ സ്ഥിരമായി വെളിപ്പെടുത്തുന്നുവെന്ന് പഠിക്കുക. ക്രിസ്തീയ ഏകദൈവാരാധന ത്രിത്വപരമാണെന്ന് മനസ്സിലാക്കുക: മൂന്നു വ്യക്തികളിൽ ഒരു ദൈവം - പിതാവ്, പുത്രൻ, പരിശുദ്ധാത്മാവ് - വ്യത്യസ്തരായെങ്കിലും സത്തയിൽ ഐക്യപ്പെട്ടിരിക്കുന്നു. ഈ പഠനം തെറ്റായ മതങ്ങൾക്കും വിഗ്രഹാരാധനയ്ക്കും ആപേക്ഷികവാദത്തിനും എതിരായി ബൈബിളിലെ ദൈവത്തിന്റെ അനന്യതയെ പ്രതിരോധിക്കാൻ നിങ്ങളെ സജ്ജമാക്കുകയും നിങ്ങളുടെ വിശ്വാസത്തെ വേദപുസ്തകത്തിന്റെ വ്യക്തമായ സാക്ഷ്യത്തിൽ അടിസ്ഥാനമാക്കുകയും ദൈവത്തിന്റെ മഹത്വത്തിന്റെ സത്യം വ്യക്തമാക്കാൻ നിങ്ങളെ തയ്യാറാക്കുകയും ചെയ്യുന്നു.'
WHERE topic_id = '666e8400-e29b-41d4-a716-446655440001' AND language_code = 'ml';

UPDATE recommended_topics_translations
SET description = 'യേശുക്രിസ്തു എന്തുകൊണ്ടാണ് രക്ഷയുടെ ഏക മാർഗമെന്ന് കണ്ടെത്തുക, അവൻ തന്നെ പ്രഖ്യാപിച്ചതുപോലെ: "ഞാൻ വഴിയും സത്യവും ജീവനുമാകുന്നു. എന്നിലൂടെയല്ലാതെ ആരും പിതാവിന്റെ അടുക്കൽ വരുന്നില്ല" (യോഹന്നാൻ 14:6). ദൈവത്തിന്റെ അവതാരമെന്ന നിലയിൽ യേശുവിന്റെ അനന്യമായ സ്വത്വം, അവന്റെ പാപരഹിത ജീവിതം, പകരക്കാരനായ മരണം, ശരീര പുനരുത്ഥാനം എന്നിവ ദൈവത്തിനും മനുഷ്യരാശിക്കും ഇടയിലുള്ള ഏക ഇടനിലക്കാരനായി അവനെ എങ്ങനെ മാറ്റുന്നുവെന്ന് പഠിക്കുക (1 തിമൊഥെയൊസ് 2:5). എല്ലാ വഴികളും ദൈവത്തിലേക്ക് നയിക്കുന്നു എന്ന ആശയമായ മതപരമായ ബഹുസ്വരത വേദപുസ്തകത്തെയും സുവിശേഷത്തെയും എന്തുകൊണ്ട് വൈരുദ്ധ്യപ്പെടുത്തുന്നുവെന്ന് മനസ്സിലാക്കുക. ഈ പഠനം ബൈബിളിലെ സത്യത്തിൽ അടിസ്ഥാനമാക്കിയതും നഷ്ടപ്പെട്ടവരോടുള്ള സ്നേഹത്താലും ദൈവമഹത്വത്തോടുള്ള തീക്ഷ്ണതയാലും പ്രചോദിതമായതുമായ ബഹുസ്വര ലോകത്ത് കൃപയോടെയും എന്നാൽ ഉറച്ചും ക്രിസ്തുവിന്റെ പ്രത്യേക അവകാശവാദങ്ങൾ പ്രഖ്യാപിക്കാൻ നിങ്ങളെ സജ്ജമാക്കുന്നു.'
WHERE topic_id = '666e8400-e29b-41d4-a716-446655440002' AND language_code = 'ml';

UPDATE recommended_topics_translations
SET description = 'ദൈവത്തിന്റെ ആത്മാവ് നൽകിയതും പിശകില്ലാത്തതുമായ ദൈവവചനം എന്ന നിലയിൽ ബൈബിളിന്റെ വിശ്വാസ്യതയ്ക്കും വിശ്വാസയോഗ്യതയ്ക്കുമുള്ള ആകർഷകമായ തെളിവുകൾ പരിശോധിക്കുക. പഴയ കൈയ്യെഴുത്ത് കോപ്പികളിലെ തെളിവ്, പഴയ ഉത്ഖനനങ്ങളിൽ നിന്നുള്ള കണ്ടെത്തലുകൾ, പൂർത്തീകരിക്കപ്പെട്ട പ്രവചനം, ഉൾപ്പൊരുത്തം, പരിശുദ്ധാത്മാവിന്റെ സാക്ഷ്യം എന്നിവയെല്ലാം വേദപുസ്തകം ദൈവത്തിൽ നിന്ന് വന്നതാണെന്നും അതിന്റെ അധികാരത്തെയും എങ്ങനെ സ്ഥിരീകരിക്കുന്നുവെന്ന് പഠിക്കുക. ബൈബിളിന്റെ വിശ്വാസ്യത മനുഷ്യരുടെ അഭിപ്രായത്തിലോ പണ്ഡിത സമവായത്തിലോ അടിസ്ഥാനമാക്കിയതല്ല, മറിച്ച് നുണ പറയാൻ കഴിയാത്ത സത്യത്തിന്റെ ദൈവത്തിന്റെ സ്വഭാവത്തിലാണെന്ന് മനസ്സിലാക്കുക. ഈ പഠനം സംശയിക്കുന്നവരുടെ എതിർപ്പുകൾക്ക് ഉത്തരം നൽകാനും ദൈവവചനത്തിലുള്ള നിങ്ങളുടെ ആത്മവിശ്വാസം ശക്തിപ്പെടുത്താനും സിദ്ധാന്തത്തിന്റെയും ജീവിതത്തിന്റെയും എല്ലാ കാര്യങ്ങളിലും വിശ്വാസത്തിനും പ്രയോഗത്തിനുമുള്ള അന്തിമ അധികാരമായി വേദപുസ്തകത്തിന്റെ അടിത്തറയിൽ ഉറച്ചുനിൽക്കാനും നിങ്ങളെ സജ്ജമാക്കുന്നു.'
WHERE topic_id = '666e8400-e29b-41d4-a716-446655440003' AND language_code = 'ml';

UPDATE recommended_topics_translations
SET description = 'പരിശുദ്ധാത്മാവ് ഹൃദയങ്ങളെ ബോധ്യപ്പെടുത്തുകയും പാപികളെ രക്ഷിക്കുകയും ചെയ്യുന്നുവെന്ന് വിശ്വസിച്ചുകൊണ്ട്, വ്യക്തത, ധൈര്യം, സ്നേഹം എന്നിവയോടെ സുവിശേഷം പങ്കുവെക്കുന്നതിനുള്ള പ്രായോഗികവും ബൈബിളധിഷ്ഠിതവുമായ രീതികൾ പഠിക്കുക (യോഹന്നാൻ 16:8, റോമർ 1:16). സുവിശേഷസന്ദേശത്തിന്റെ അത്യാവശ്യ ഘടകങ്ങൾ മനസ്സിലാക്കുക - ദൈവത്തിന്റെ വിശുദ്ധി, മാനുഷിക പാപം, ക്രിസ്തുവിന്റെ പകരക്കാരനായ മരണവും പുനരുത്ഥാനവും, മാനസാന്തരപ്പെടാനും വിശ്വസിക്കാനുമുള്ള ആഹ്വാനം - ദൈനംദിന സംഭാഷണങ്ങളിൽ അവ എങ്ങനെ ആകർഷകമായി ആശയവിനിമയം നടത്താമെന്ന്. ഭയത്തെ എങ്ങനെ മറികടക്കാമെന്നും എതിർപ്പുകൾ മുൻകൂട്ടി കാണാമെന്നും മനുഷ്യ വാഗ്മിതയ്ക്ക് പകരം ദൈവവചനത്തിന്റെ ശക്തിയിൽ വിശ്വസിക്കാമെന്നും കണ്ടെത്തുക. ഈ പഠനം സ്വാഭാവിക സന്ദർഭങ്ങളിൽ, ബന്ധങ്ങളിലൂടെ, നഷ്ടപ്പെട്ടവരോടുള്ള യഥാർത്ഥ സ്നേഹത്തോടെ, എല്ലായ്പ്പോഴും രക്ഷ ദൈവത്തിന്റെ കൈകളിലാണ് എന്ന് ആശ്രയിച്ചുകൊണ്ട് ക്രിസ്തുവിനെ വിശ്വസ്തതയോടെ പങ്കുവെക്കാൻ നിങ്ങളെ സജ്ജമാക്കുന്നു.'
WHERE topic_id = '888e8400-e29b-41d4-a716-446655440004' AND language_code = 'ml';

UPDATE recommended_topics_translations
SET description = 'ഓരോ ഗോത്രം, ഭാഷ, രാഷ്ട്രം എന്നിവയിൽ നിന്നും ആരാധകരെ ശേഖരിക്കാനുള്ള ദൈവത്തിന്റെ ആഗോള ദൗത്യത്തിൽ പങ്കെടുക്കുന്ന രാഷ്ട്രങ്ങൾക്കായി പ്രാർത്ഥിക്കാനുള്ള ബൈബിളിലെ ആഹ്വാനം കണ്ടെത്തുക (വെളിപാട് 7:9). എത്താത്ത ആളുകൾക്കും പീഡിപ്പിക്കപ്പെടുന്ന വിശ്വാസികൾക്കും സുവിശേഷ പുരോഗതിക്കും വേണ്ടി മറ്റുള്ളവർക്കുവേണ്ടി ഇടനിലക്കാരനായി ചെയ്യുന്ന പ്രാർത്ഥന ക്രിസ്തുവിന്റെ പ്രഖ്യാപനത്തിലൂടെ ലോകമെമ്പാടും പാപികളെ രക്ഷിക്കാനുള്ള ദൈവത്തിന്റെ മഹത്തായ പദ്ധതിയുമായി എങ്ങനെ യോജിക്കുന്നുവെന്ന് പഠിക്കുക. വിശ്വസ്ത പ്രാർത്ഥന മിഷണറിമാരെ എങ്ങനെ പിന്തുണയ്ക്കുന്നുവെന്നും സുവിശേഷത്തിനായി വാതിലുകൾ തുറക്കുന്നുവെന്നും യേശുവിന്റെ നാമം ഇതുവരെ അറിയപ്പെടാത്ത സ്ഥലങ്ങളിൽ ദൈവരാജ്യം മുന്നോട്ട് കൊണ്ടുപോകുന്നുവെന്നും മനസ്സിലാക്കുക. ഈ പഠനം മിഷനുകൾക്കായി ആഗോള കാഴ്ചപ്പാട് വികസിപ്പിക്കാനും നിർദ്ദിഷ്ട ആവശ്യങ്ങൾക്കായി തന്ത്രപരമായി പ്രാർത്ഥിക്കാനും തന്റെ മഹത്വത്തിനും സുവിശേഷ വ്യാപനത്തിനുമായി രാഷ്ട്രങ്ങൾക്കിടയിൽ തന്റെ ഉദ്ദേശ്യങ്ങൾ നിറവേറ്റാൻ ദൈവത്തെ വിശ്വസിക്കാനും വിശ്വാസികളെ പ്രചോദിപ്പിക്കുന്നു.'
WHERE topic_id = '888e8400-e29b-41d4-a716-446655440005' AND language_code = 'ml';

-- 111-003 hi: replace "वस्तुनिष्ठ सच्चाई" and "बौद्धिक सहमति"
UPDATE recommended_topics_translations
SET description = 'जानें कि सच्चे विश्वासी कैसे निश्चित रूप से जान सकते हैं कि उनके पास उद्धार है, जो मसीह के पूर्ण कार्य और परमेश्वर के वचन की अपरिवर्तनीय प्रतिज्ञाओं पर आधारित है - न कि उनके अपने प्रदर्शन, भावनाओं, या उतार-चढ़ाव वाली भावनाओं पर। समझें कि आश्वासन सुसमाचार की स्पष्ट और ठोस सच्चाई से आता है, पवित्र आत्मा की आंतरिक गवाही जो पुष्टि करती है कि आप परमेश्वर की संतान हैं (रोमियों 8:16), और सच्चे विश्वास का प्रमाण जो आपके जीवन में आत्मिक फल उत्पन्न करता है। यह अध्ययन बचाने वाले विश्वास और केवल मन से सहमत होने के बीच अंतर करता है, संदेहों को बाइबिलीय रूप से संबोधित करता है, और पुष्टि करता है कि जो वास्तव में फिर से जन्मे हैं, वे परमेश्वर की शक्ति द्वारा सुरक्षित रखे जाते हैं (1 पतरस 1:5, यूहन्ना 10:28-29) और अंत तक विश्वास में बने रहेंगे। आश्वासन के तीन आधारों की खोज करें: शास्त्र में परमेश्वर की प्रतिज्ञाएं (1 यूहन्ना 5:13), भीतर आत्मा की गवाही, और सच्चे परिवर्तन से बहने वाला परिवर्तित जीवन (2 कुरिन्थियों 5:17, 1 यूहन्ना 3:14)।'
WHERE topic_id = '111e8400-e29b-41d4-a716-446655440003' AND language_code = 'hi';

-- 111-006 hi: replace "पुनर्जन्म" (theological) and "पवित्रीकरण"
UPDATE recommended_topics_translations
SET description = 'पवित्र आत्मा के कार्य को समझें - परमेश्वर का तीसरा व्यक्ति, पिता और पुत्र के साथ समान - मसीही जीवन में। जानें कि पवित्र आत्मा उद्धार में कैसे कार्य करता है (पश्चाताप और विश्वास की ओर पापियों को आश्वस्त करना), विश्वासियों को नया जीवन देने में, उन्हें बदलने और पवित्र करने में, और सेवा में (सेवा के लिए उपहार और शक्ति प्रदान करना)। समझें कि कैसे आत्मा आपको सत्य में मार्गदर्शन करता है, मसीह की समानता में आकार देता है, और आपको परमेश्वर के राज्य के लिए प्रभावी सेवा के लिए सशक्त बनाता है। यह अध्ययन सामान्य गलतफहमियों को सुधारता है और पवित्र आत्मा की पूर्ण भूमिका की बाइबिल-आधारित समझ स्थापित करता है — क्योंकि यही वह आत्मा है जो विश्वासियों में वास करता है और उन्हें मसीह की समानता में बदलता है।'
WHERE topic_id = '111e8400-e29b-41d4-a716-446655440006' AND language_code = 'hi';

-- 333-001 hi: replace "सार्वभौमिक कलीसिया"
UPDATE recommended_topics_translations
SET description = 'कलीसिया के बाइबिल सिद्धांत को मसीह के शरीर के रूप में खोजें - सभी सच्चे विश्वासियों की सभा जिन्हें दुनिया से परमेश्वर की आराधना करने, सुसमाचार घोषित करने और मुखिया मसीह की आज्ञाकारिता में जीने के लिए बुलाया गया है। जानें कि कलीसिया केवल एक इमारत या संस्था नहीं है, बल्कि एक आत्मिक जीव है जो मसीह में विश्वास से एकजुट है और पवित्र आत्मा द्वारा वास किया गया है। कलीसिया के उद्देश्यों को समझें: आराधना, शिष्यत्व, संगति, सुसमाचार प्रचार और सेवा। यह अध्ययन सभी समय के सभी विश्वासियों की कलीसिया और स्थानीय कलीसिया (एकत्रित मंडलियां) के बीच अंतर करता है, एक स्थानीय निकाय के प्रति प्रतिबद्धता के महत्व पर जोर देता है जहां विश्वासी सुसज्जित, चरवाही और जवाबदेह ठहराए जाते हैं जब वे एक साथ मसीह-समानता में बढ़ते हैं।'
WHERE topic_id = '333e8400-e29b-41d4-a716-446655440001' AND language_code = 'hi';

-- 333-005 hi: replace "शानदार अभिव्यक्तियों"
UPDATE recommended_topics_translations
SET description = 'आत्मिक वरदानों पर बाइबिल की शिक्षा की खोज करें - पवित्र आत्मा द्वारा हर विश्वासी को कलीसिया के निर्माण और परमेश्वर की महिमा के लिए दी गई क्षमताएं (1 कुरिन्थियों 12:7)। जानें कि अपने आत्मिक वरदानों की पहचान कैसे करें, वफादार सेवा के माध्यम से उन्हें विकसित करें, और मसीह के शरीर को मजबूत करने के लिए प्रेम और विनम्रता में उनका उपयोग करें। आत्मिक वरदानों के उद्देश्य को समझें: व्यक्तिगत प्रतिष्ठा या आत्म-पूर्ति नहीं, बल्कि दूसरों को विश्वास और परिपक्वता में बनाना (इफिसियों 4:11-13)। यह अध्ययन आत्मिक वरदानों की उपेक्षा और अद्भुत चिह्नों की तलाश दोनों से बचाता है, कलीसिया के भीतर उपहार की सभी अभिव्यक्तियों में प्रबंधन, सेवा और प्रेम की सर्वोच्चता के बाइबिल सिद्धांतों में आपको स्थापित करता है।'
WHERE topic_id = '333e8400-e29b-41d4-a716-446655440005' AND language_code = 'hi';

-- 888-004 hi: replace "प्रतिस्थापनात्मक मृत्यु" and "संप्रभुता"
UPDATE recommended_topics_translations
SET description = 'स्पष्टता, साहस और प्रेम के साथ सुसमाचार साझा करने के लिए व्यावहारिक, बाइबिल तरीके सीखें, यह विश्वास करते हुए कि पवित्र आत्मा हृदयों को दोषी ठहराता है और पापियों को बचाता है (यूहन्ना 16:8, रोमियों 1:16)। सुसमाचार संदेश के आवश्यक तत्वों को समझें - परमेश्वर की पवित्रता, मानव पाप, मसीह की हमारी जगह हुई मृत्यु और पुनरुत्थान, और पश्चाताप करने और विश्वास करने का आह्वान - और रोज़मर्रा की बातचीत में उन्हें आकर्षक रूप से कैसे संप्रेषित करें। जानें कि भय पर कैसे काबू पाएं, आपत्तियों का अनुमान लगाएं, और मानव वाक्पटुता या हेरफेर के बजाय परमेश्वर के वचन की शक्ति पर भरोसा करें। यह अध्ययन आपको प्राकृतिक संदर्भों में, रिश्तों के माध्यम से, और खोए हुओं के लिए वास्तविक प्रेम के साथ, हमेशा उद्धार में परमेश्वर की प्रभुता पर निर्भर रहते हुए, वफादारी से मसीह को साझा करने के लिए सुसज्जित करता है।'
WHERE topic_id = '888e8400-e29b-41d4-a716-446655440004' AND language_code = 'hi';

-- AAA-001 hi: replace "वस्तुनिष्ठ नैतिक मूल्यों"
UPDATE recommended_topics_translations
SET description = 'ब्रह्मांडीय तर्क (ब्रह्मांड को एक प्रथम कारण की आवश्यकता है), उद्देश्यपूर्ण तर्क (सृष्टि में डिज़ाइन एक डिज़ाइनर की ओर इशारा करता है), और नैतिक तर्क (सच्चे नैतिक मूल्यों को एक नैतिक विधायक की आवश्यकता है) के माध्यम से परमेश्वर के अस्तित्व के लिए आकर्षक दार्शनिक और बाइबिलीय साक्ष्य की जांच करें। खोजें कि कैसे सृष्टि स्वयं परमेश्वर की महिमा की घोषणा करती है (भजन संहिता 19:1, रोमियों 1:20), और कैसे मानव विवेक और तर्क उसकी वास्तविकता की गवाही देते हैं। जानें कि ये तर्क शास्त्र की सीधी घोषणा को कैसे पूरक करते हैं: "मूर्ख अपने मन में कहता है, ''कोई परमेश्वर नहीं है''" (भजन संहिता 14:1), जो आपको अपने भीतर की आशा का कारण देने के लिए सुसज्जित करता है (1 पतरस 3:15)।'
WHERE topic_id = 'AAA00000-e29b-41d4-a716-446655440001' AND language_code = 'hi';

-- AAA-002 hi: replace "संप्रभुता" with "प्रभुता"
UPDATE recommended_topics_translations
SET description = 'विश्वास के सबसे कठिन प्रश्नों में से एक से जूझें, सभी चीजों पर परमेश्वर की पूर्ण प्रभुता को समझते हुए, जबकि पाप के लिए मानव नैतिक जिम्मेदारी की पुष्टि करते हुए (उत्पत्ति 3, रोमियों 5:12)। जानें कि कैसे बुराई और पीड़ा मानवता के विद्रोह के माध्यम से संसार में प्रवेश की, न कि परमेश्वर की डिज़ाइन से, और कैसे परमेश्वर अपनी प्रभुता में अपने मुक्तिदायक उद्देश्यों के लिए बुराई का भी उपयोग करता है (उत्पत्ति 50:20, रोमियों 8:28)। परमेश्वर की भलाई, मानव स्वतंत्र इच्छा, और एक पतित दुनिया की वास्तविकता के बीच बाइबिलीय तनाव की खोज करें जो छुटकारे के लिए कराह रही है (रोमियों 8:18-25)। परमेश्वर के चरित्र पर भरोसा करना सीखें, भले ही उसके मार्ग हमारी समझ से परे हों (यशायाह 55:8-9), यह जानते हुए कि उसने हमारी ओर से मसीह की पीड़ा के माध्यम से अपने प्रेम को सर्वोत्तम रूप से प्रदर्शित किया (रोमियों 5:8)।'
WHERE topic_id = 'AAA00000-e29b-41d4-a716-446655440002' AND language_code = 'hi';

-- AAA-007 hi: replace "संप्रभु पूर्वनियति", "अर्ध-पेलागियनवाद", "अति-कैल्विनवाद"
UPDATE recommended_topics_translations
SET description = 'परमेश्वर का पहले से चुनाव (इफिसियों 1:4-5, रोमियों 8:29-30) और विश्वास करने और पश्चाताप करने के लिए मानव जिम्मेदारी (प्रेरितों के काम 17:30, यूहन्ना 3:16-18) के बीच बाइबिलीय तनाव को नेविगेट करें। समझें कि शास्त्र निडरता से दोनों सत्यों की पुष्टि करता है बिना यह समझाए कि वे एक साथ कैसे फिट होते हैं: परमेश्वर ने दुनिया की नींव से पहले अपने चुने हुए लोगों को चुना, फिर भी लोग सुसमाचार के प्रति अपनी प्रतिक्रिया के लिए वास्तव में जिम्मेदार हैं। सुधारवादी जोर की खोज करें उद्धार में परमेश्वर की पूर्ण प्रभुता पर और आर्मिनियन जोर मानव स्वतंत्र इच्छा और प्रतिरोधी अनुग्रह पर, यह पहचानते हुए कि ईमानदार विश्वासी दोनों विचारों को रखते हैं। चरम त्रुटियों से बचें - वह जो मानव जिम्मेदारी को नकारती है, या वह जो परमेश्वर की प्रभुता को कम करती है। परमेश्वर की रहस्यमय बुद्धि में विश्राम करें (रोमियों 11:33-36) जबकि तत्कालता से सभी को सुसमाचार की घोषणा करें, यह जानते हुए कि परमेश्वर अपने उद्देश्यों को पूरा करने के लिए मानव साधनों का उपयोग करता है (रोमियों 10:14-17)।'
WHERE topic_id = 'AAA00000-e29b-41d4-a716-446655440007' AND language_code = 'hi';

-- AAA-008 hi: replace "धर्मशास्त्रीय"
UPDATE recommended_topics_translations
SET description = 'प्रारंभिक कलीसिया से सुधार और आधुनिक संप्रदायों के विकास तक कलीसिया के इतिहास को समझें, यह सीखते हुए कि सांस्कृतिक, विश्वास संबंधी और व्यावहारिक अंतरों ने विभिन्न परंपराओं के गठन को कैसे प्रेरित किया। आवश्यक सिद्धांतों के बीच अंतर करें जो रूढ़िवादी ईसाई धर्म को परिभाषित करते हैं (सुसमाचार, त्रिएकता, शास्त्र का अधिकार, विश्वास के माध्यम से अनुग्रह द्वारा उद्धार) और गैर-आवश्यक मामलों में जहां ईमानदार विश्वासी भिन्न हो सकते हैं (बपतिस्मा की विधि, कलीसिया सरकार, आत्मिक वरदान, अंत समय के दृष्टिकोण)। प्राचीन कहावत लागू करें: "आवश्यक चीजों में, एकता; गैर-आवश्यक चीजों में, स्वतंत्रता; सभी चीजों में, दान।" अनावश्यक विभाजन के लिए शोक करें जो गर्व, व्यक्तित्व संघर्ष, या तुच्छ विवादों के कारण हुआ, जबकि यह पहचानते हुए कि कुछ अलगाव सुसमाचार सत्य को संरक्षित करने के लिए आवश्यक थे (गलातियों 1:6-9)। मसीह और उसके वचन के लिए साझा प्रतिबद्धता के आधार पर वास्तविक एकता का पीछा करें (इफिसियों 4:1-6), न कि सतही सर्वव्यापकता जो बाइबिलीय सत्य से समझौता करती है।'
WHERE topic_id = 'AAA00000-e29b-41d4-a716-446655440008' AND language_code = 'hi';

-- 222-008 hi: replace "वस्तुनिष्ठ सत्य" and "व्यक्तिपरक भावनाओं"
UPDATE recommended_topics_translations
SET description = 'परिपक्व विश्वासियों को भी परेशान करने वाले संदेह और भय पर काबू पाने के लिए बाइबिलीय रणनीतियों को जानें। अपने मन को शास्त्र के स्पष्ट और ठोस सत्य से संतृप्त करके संदेह से लड़ें, न कि मन की भावनाओं पर निर्भर रहकर (भजन संहिता 119:11, रोमियों 10:17), अपने जीवन में और इतिहास में परमेश्वर की पिछली विश्वासयोग्यता को याद करते हुए (भजन संहिता 77:11-12), और अपने प्रश्नों को ईमानदारी से परमेश्वर के पास लाते हुए जो ईमानदार खोजकर्ताओं का स्वागत करता है (मरकुस 9:24)। भय पर काबू पाएं परमेश्वर के पूर्ण प्रेम पर ध्यान करके जो भय को दूर करता है (1 यूहन्ना 4:18), सभी परिस्थितियों पर उसके प्रभु के नियंत्रण (मत्ती 10:29-31), और उसकी प्रतिज्ञाओं को कभी नहीं छोड़ने या त्यागने के लिए (इब्रानियों 13:5-6)। चिंतित विचारों को प्रार्थना और धन्यवाद से बदलें, परमेश्वर की शांति को अपने दिल और दिमाग की रक्षा करने दें (फिलिप्पियों 4:6-7)। याद रखें कि विश्वास संदेह या भय की अनुपस्थिति नहीं है, बल्कि उनके बावजूद परमेश्वर पर भरोसा करना है, अपनी भावनाओं पर उसके वचन को विश्वास करना चुनना है।'
WHERE topic_id = '222e8400-e29b-41d4-a716-446655440008' AND language_code = 'hi';

-- 444-006 hi: replace "वस्तुनिष्ठ सत्य" and "व्यक्तिपरक भावनाओं"
UPDATE recommended_topics_translations
SET description = 'विश्वास से जीने (परमेश्वर के स्पष्ट सत्य पर भरोसा करना) और भावनाओं से जीने (मन की भावनाओं पर भरोसा करना) के बीच महत्वपूर्ण अंतर सीखें। समझें कि बाइबिलीय विश्वास एक तर्कहीन छलांग या इच्छाधारी सोच नहीं है, बल्कि शास्त्र में प्रकट परमेश्वर के सिद्ध चरित्र और प्रतिज्ञाओं में आत्मविश्वासपूर्ण विश्वास है (इब्रानियों 11:1, रोमियों 10:17)। पहचानें कि भावनाएं वास्तविक हैं लेकिन अविश्वसनीय मार्गदर्शक हैं - वे परिस्थितियों, हार्मोन, नींद, और अनगिनत अन्य कारकों के आधार पर उतार-चढ़ाव करती हैं, जबकि परमेश्वर का वचन हमेशा अपरिवर्तित रहता है (यशायाह 40:8, मत्ती 24:35)। विश्वास से चलने का अभ्यास करें जब आप परमेश्वर की उपस्थिति महसूस नहीं करते, जब प्रार्थनाएं अनुत्तरित लगती हैं, जब परिस्थितियां निराशाजनक दिखाई देती हैं, या जब संदेह आपके दिमाग पर हमला करते हैं (2 कुरिन्थियों 5:7, हबक्कूक 3:17-19)। शास्त्र पर ध्यान करके, परमेश्वर की पिछली विश्वासयोग्यता को याद करके, और दैनिक रूप से यह विश्वास करना चुनकर विश्वास बनाएं कि परमेश्वर अपने बारे में, आपकी पहचान, और आपके भविष्य के बारे में क्या कहता है, भले ही आप कैसा महसूस करते हैं। भरोसा रखें कि दृढ़ विश्वास भावनात्मक ऊंचाइयों की तुलना में परमेश्वर का बहुत अधिक सम्मान करता है, और वह उन लोगों को पुरस्कृत करता है जो उसे मेहनती से खोजते हैं (इब्रानियों 11:6)।'
WHERE topic_id = '444e8400-e29b-41d4-a716-446655440006' AND language_code = 'hi';

-- 111-003 ml: replace "ബൗദ്ധിക സമ്മതം" and "വസ്തുനിഷ്ഠ"
UPDATE recommended_topics_translations
SET description = 'യഥാർത്ഥ വിശ്വാസികൾക്ക് അവർക്ക് രക്ഷ ഉണ്ടെന്ന് എങ്ങനെ ഉറപ്പോടെ അറിയാമെന്ന് പഠിക്കുക, അത് ക്രിസ്തുവിന്റെ പൂർത്തിയായ പ്രവൃത്തിയിലും ദൈവവചനത്തിന്റെ മാറ്റമില്ലാത്ത വാഗ്ദാനങ്ങളിലും അധിഷ്ഠിതമാണ് - അവരുടെ സ്വന്തം പ്രകടനത്തിലോ വികാരങ്ങളിലോ ഏറ്റക്കുറച്ചിലുകളിലോ അല്ല. ഉറപ്പ് സുവിശേഷത്തിന്റെ വ്യക്തവും ഉറപ്പുള്ള സത്യത്തിൽ നിന്നും, നിങ്ങൾ ദൈവത്തിന്റെ മകനാണെന്ന് സ്ഥിരീകരിക്കുന്ന പരിശുദ്ധാത്മാവിന്റെ ആന്തരിക സാക്ഷ്യത്തിൽ നിന്നും (റോമർ 8:16), നിങ്ങളുടെ ജീവിതത്തിൽ ആത്മീയ ഫലം ഉൽപാദിപ്പിക്കുന്ന യഥാർത്ഥ വിശ്വാസത്തിന്റെ തെളിവിൽ നിന്നും എങ്ങനെ വരുന്നുവെന്ന് മനസ്സിലാക്കുക. ഈ പഠനം രക്ഷിക്കുന്ന വിശ്വാസവും കേവലം മനസ്സുകൊണ്ട് സമ്മതിക്കലും തമ്മിൽ വേർതിരിക്കുന്നു, സംശയങ്ങളെ ബൈബിൾപരമായി അഭിസംബോധന ചെയ്യുന്നു, യഥാർത്ഥമായി പുനർജനിച്ചവർ ദൈവശക്തിയാൽ സുരക്ഷിതരായി സൂക്ഷിക്കപ്പെടുന്നുവെന്നും (1 പത്രോസ് 1:5, യോഹന്നാൻ 10:28-29) അവസാനംവരെ വിശ്വാസത്തിൽ ഉറച്ചുനിൽക്കുമെന്നും സ്ഥിരീകരിക്കുന്നു. ഉറപ്പിന്റെ മൂന്ന് അടിസ്ഥാനങ്ങൾ കണ്ടെത്തുക: തിരുവെഴുത്തിലെ ദൈവവാഗ്ദാനങ്ങൾ (1 യോഹന്നാൻ 5:13), ഉള്ളിലുള്ള ആത്മാവിന്റെ സാക്ഷ്യം, യഥാർത്ഥ മാറ്റത്തിൽ നിന്ന് ഒഴുകുന്ന പരിവർത്തിത ജീവിതം (2 കൊരിന്ത്യർ 5:17, 1 യോഹന്നാൻ 3:14).'
WHERE topic_id = '111e8400-e29b-41d4-a716-446655440003' AND language_code = 'ml';

-- 111-006 ml: replace "പുനർജനനത്തിൽ" and "വിശുദ്ധീകരണത്തിൽ"
UPDATE recommended_topics_translations
SET description = 'പരിശുദ്ധാത്മാവിന്റെ പ്രവൃത്തി മനസ്സിലാക്കുക - ദൈവത്തിന്റെ മൂന്നാമത്തെ വ്യക്തി, പിതാവിനോടും പുത്രനോടും തുല്യമായ - ക്രിസ്തീയ ജീവിതത്തിൽ. പരിശുദ്ധാത്മാവ് രക്ഷയിൽ (പാപികളെ മാനസാന്തരത്തിലേക്കും വിശ്വാസത്തിലേക്കും ബോധ്യപ്പെടുത്തുന്നു), വിശ്വാസികൾക്ക് പുതിയ ജീവൻ നൽകുന്നതിൽ, അവരെ വളർത്തി വിശ്വാസത്തിൽ ശക്തരാക്കുന്നതിൽ, സേവനത്തിൽ (സേവനത്തിനുള്ള വരദാനങ്ങളും ശക്തിയും നൽകുന്നു) എങ്ങനെ പ്രവർത്തിക്കുന്നുവെന്ന് പഠിക്കുക. ആത്മാവ് നിങ്ങളെ സത്യത്തിലേക്ക് എങ്ങനെ നയിക്കുന്നുവെന്നും ക്രിസ്തുവിന്റെ സാദൃശ്യത്തിൽ രൂപപ്പെടുത്തുന്നുവെന്നും ദൈവരാജ്യത്തിനായുള്ള ഫലപ്രദമായ സേവനത്തിന് നിങ്ങളെ ശക്തീകരിക്കുന്നുവെന്നും മനസ്സിലാക്കുക. ഈ പഠനം തെറ്റിദ്ധാരണകൾ തിരുത്തുകയും ബൈബിളധിഷ്ഠിതമായ ധാരണ സ്ഥാപിക്കുകയും ചെയ്യുന്നു.'
WHERE topic_id = '111e8400-e29b-41d4-a716-446655440006' AND language_code = 'ml';

-- 333-002 ml: replace "വിട്ടുവീഴ്ച ചെയ്യാനാവാത്ത"
UPDATE recommended_topics_translations
SET description = 'പ്രാദേശിക സഭയ്ക്കുള്ളിലെ ക്രിസ്തീയ കൂട്ടായ്മയുടെ ഒഴിവാക്കാൻ പറ്റാത്ത പ്രാധാന്യം കണ്ടെത്തുക. വിശ്വാസികൾ ഒരുമിച്ചു കൂടുന്നത് ഉപേക്ഷിക്കരുതെന്ന് വേദപുസ്തകം എന്തുകൊണ്ട് കൽപ്പിക്കുന്നുവെന്ന് പഠിക്കുക (എബ്രായർ 10:25), കാരണം ആത്മീയ വളർച്ച, ഉത്തരവാദിത്തം, പ്രോത്സാഹനം, തെറ്റായ പഠിപ്പിക്കലിൽ നിന്നുള്ള സംരക്ഷണം എന്നിവയ്ക്ക് മറ്റ് ക്രിസ്ത്യാനികളുമായി പ്രതിബദ്ധമായ ബന്ധങ്ങൾ ആവശ്യമാണ്. സാധാരണ സാമൂഹികവൽക്കരണത്തേക്കാൾ കൂടുതലായി കൂട്ടായ്മയെ മനസ്സിലാക്കുക - ഇത് ക്രിസ്തുവിലെ പങ്കിട്ട ജീവിതമാണ്, പരസ്പര സ്നേഹം, സത്യം പറയൽ, ഏറ്റുപറച്ചിൽ, പ്രാർത്ഥന, ആത്മീയ വരദാനങ്ങളുടെ പ്രയോഗം എന്നിവയാൽ സവിശേഷമാണ്. ഈ പഠനം സാംസ്കാരിക വ്യക്തിത്വത്തെ വെല്ലുവിളിക്കുകയും ക്രിസ്തുവിന്റെ ശരീരത്തിനുള്ളിൽ ആഴത്തിലുള്ളതും ഉദ്ദേശിച്ചതുമായ ബന്ധങ്ങളിലേക്ക് വിശ്വാസികളെ വിളിക്കുകയും ചെയ്യുന്നു, അവിടെ ഇരുമ്പ് ഇരുമ്പിനെ മൂർച്ചയാക്കുകയും (സദൃശവാക്യങ്ങൾ 27:17) ദൃശ്യമായ സമൂഹത്തിൽ സുവിശേഷം ജീവിക്കുകയും ചെയ്യുന്നു.'
WHERE topic_id = '333e8400-e29b-41d4-a716-446655440002' AND language_code = 'ml';

-- 333-004 ml: replace "സിദ്ധാന്തപരമായ", "വിഭജനകരമായ നിയമവാദ", "വിട്ടുവീഴ്ചാപരമായ ബഹുസ്വരത"
UPDATE recommended_topics_translations
SET description = 'സഭയ്ക്കുള്ളിൽ ഐക്യം പിന്തുടരാനുള്ള ബൈബിളിലെ ആഹ്വാനം പര്യവേക്ഷണം ചെയ്യുക, സുവിശേഷത്തിന്റെ സത്യത്തിൽ അടിസ്ഥാനമാക്കിയതും പരിശുദ്ധാത്മാവിനാൽ ശക്തീകരിക്കപ്പെട്ടതും. ക്രിസ്തീയ ഐക്യം കേവലം യോജിപ്പോ സഹിഷ്ണുതയോ അല്ല, മറിച്ച് ക്രിസ്തുവിലുള്ള പങ്കിട്ട വിശ്വാസത്തിലും വേദപുസ്തകത്തോടുള്ള ഭക്തിയിലും പരസ്പര സ്നേഹത്തിലും വേരൂന്നിയ ആത്മീയ ഏകതയാണെന്ന് പഠിക്കുക (യോഹന്നാൻ 17:20-23). ബൈബിൾ സത്യം ഉയർത്തിപ്പിടിച്ചുകൊണ്ട് എങ്ങനെ ഐക്യം നിലനിർത്താമെന്നും രണ്ട് അതിരുകടന്ന തെറ്റുകൾ ഒഴിവാക്കാമെന്നും മനസ്സിലാക്കുക: ഒന്ന്, ചെറിയ കാര്യങ്ങളിൽ പോലും വഴക്കുണ്ടാക്കി സഭയെ പിരിക്കുന്ന കർശന മനോഭാവം; രണ്ട്, ഐക്യം നിലനിർത്താൻ വേണ്ടി സുവിശേഷത്തിന്റെ അടിസ്ഥാന സത്യങ്ങളിൽ വിട്ടുവീഴ്ച ചെയ്യൽ. ഈ പഠനം സ്നേഹത്തോടെ പരസ്പരം സഹിക്കാനും സംഘർഷങ്ങൾ ബൈബിളനുസൃതമായി പരിഹരിക്കാനും നിരീക്ഷിക്കുന്ന ലോകത്തിന് വിശ്വാസികൾക്കിടയിലെ ദൃശ്യമായ സ്നേഹത്തിലൂടെയും യോജിപ്പിലൂടെയും സുവിശേഷത്തിന്റെ ആധികാരികത പ്രകടമാക്കാനും പഠിപ്പിക്കുന്നു, എല്ലാം ദൈവത്തിന്റെ മഹത്വത്തിനും സഭയുടെ സാക്ഷ്യത്തിനും വേണ്ടി.'
WHERE topic_id = '333e8400-e29b-41d4-a716-446655440004' AND language_code = 'ml';

-- 666-004 ml: replace "ക്ഷമാപണം" (technical apologetics term)
UPDATE recommended_topics_translations
SET description = 'മറ്റ് മതങ്ങളിലുള്ളവരുമായി ആദരവോടെയും ബൈബിൾ അനുസൃതമായും എങ്ങനെ ഇടപഴകാം, ക്രിസ്തുമതത്തെക്കുറിച്ചുള്ള അവരുടെ ചോദ്യങ്ങൾക്ക് സത്യത്തോടും കൃപയോടും കൂടി ഉത്തരം നൽകുക (1 പത്രോസ് 3:15-16). ഹിന്ദുമതം, ഇസ്ലാം, ബുദ്ധമതം, മറ്റ് മതങ്ങൾ എന്നിവയിൽ നിന്നുള്ള സാധാരണ ആക്ഷേപങ്ങൾ എങ്ങനെ മനസ്സിലാക്കാമെന്നും ബൈബിളിൽ വേരൂന്നിയ വ്യക്തവും സുവിശേഷകേന്ദ്രീകൃതവുമായ ഉത്തരങ്ങളോടെ പ്രതികരിക്കാമെന്നും പഠിക്കുക. ബൈബിൾ സത്യം പ്രതിരോധിക്കുന്നതിനും (വിശ്വാസം വ്യക്തമാക്കലും സംരക്ഷിക്കലും) ക്രിസ്തുവിനെപ്പോലെയുള്ള സ്നേഹവും വിനയവും പ്രകടിപ്പിക്കുന്നതിനും ഇടയിലുള്ള സന്തുലിതാവസ്ഥ മനസ്സിലാക്കുക. ഈ പഠനം സുവിശേഷത്തിന്റെ അനന്യത വ്യക്തമാക്കാനും തെറ്റായ മതങ്ങളുടെ അപര്യാപ്തത ചൂണ്ടിക്കാണിക്കാനും മറ്റുള്ളവരെ ഏക രക്ഷകനായ യേശുവിലേക്ക് ചൂണ്ടിക്കാണിക്കാനും നിങ്ങളെ തയ്യാറാക്കുന്നു - ക്രിസ്തുവിനെ ഇതുവരെ അറിയാത്ത ആളുകളുടെ ആത്മാക്കളോടുള്ള യഥാർത്ഥ ഉൽക്കണ്ഠ നിലനിർത്തിക്കൊണ്ട്.'
WHERE topic_id = '666e8400-e29b-41d4-a716-446655440004' AND language_code = 'ml';

-- AAA-001 ml: replace "വസ്തുനിഷ്ഠ"
UPDATE recommended_topics_translations
SET description = 'പ്രപഞ്ച വാദം (പ്രപഞ്ചത്തിന് ഒരു പ്രഥമ കാരണം ആവശ്യമാണ്), ലക്ഷ്യ വാദം (സൃഷ്ടിയിലെ രൂപകൽപ്പന ഒരു രൂപകല്പകനെ സൂചിപ്പിക്കുന്നു), ധാർമ്മിക വാദം (യഥാർത്ഥ ധാർമ്മിക മൂല്യങ്ങൾക്ക് ഒരു ധാർമ്മിക നിയമദാതാവിനെ ആവശ്യമാണ്) എന്നിവയിലൂടെ ദൈവത്തിന്റെ അസ്തിത്വത്തിനുള്ള ശ്രദ്ധേയമായ ദാർശനികവും ബൈബിൾപരവുമായ തെളിവുകൾ പരിശോധിക്കുക. സൃഷ്ടി തന്നെ ദൈവത്തിന്റെ മഹത്വം എങ്ങനെ പ്രഖ്യാപിക്കുന്നുവെന്നും (സങ്കീർത്തനം 19:1, റോമർ 1:20), മനുഷ്യ മനസ്സാക്ഷിയും യുക്തിയും അവന്റെ യാഥാർത്ഥ്യത്തിന് എങ്ങനെ സാക്ഷ്യം വഹിക്കുന്നുവെന്നും കണ്ടെത്തുക. ഈ വാദങ്ങൾ തിരുവെഴുത്തിന്റെ നേരായ പ്രഖ്യാപനത്തെ എങ്ങനെ പൂരകമാക്കുന്നുവെന്ന് കണ്ടെത്തുക: "ദൈവമില്ലെന്ന് ഭോഷൻ തന്റെ ഹൃദയത്തിൽ പറയുന്നു" (സങ്കീർത്തനം 14:1), നിങ്ങളിലെ പ്രത്യാശയ്ക്ക് ഒരു കാരണം നൽകാൻ നിങ്ങളെ സജ്ജമാക്കുന്നു (1 പത്രോസ് 3:15).'
WHERE topic_id = 'AAA00000-e29b-41d4-a716-446655440001' AND language_code = 'ml';

-- AAA-002 ml: replace "പരമാധികാരം" with "കർതൃത്വം"
UPDATE recommended_topics_translations
SET description = 'വിശ്വാസത്തിന്റെ ഏറ്റവും ബുദ്ധിമുട്ടുള്ള ചോദ്യങ്ങളിലൊന്നുമായി മല്ലിടുക, എല്ലാ കാര്യങ്ങളുടെയും മേൽ ദൈവത്തിന്റെ പൂർണ്ണ കർതൃത്വം മനസ്സിലാക്കുന്നതോടൊപ്പം പാപത്തിനുള്ള മനുഷ്യ ധാർമ്മിക ഉത്തരവാദിത്തം സ്ഥിരീകരിക്കുന്നു (ഉല്പത്തി 3, റോമർ 5:12). തിന്മയും കഷ്ടപ്പാടും ദൈവത്തിന്റെ രൂപകൽപ്പനയിലൂടെയല്ല, മനുഷ്യരാശിയുടെ മത്സരത്തിലൂടെയാണ് ലോകത്തിലേക്ക് പ്രവേശിച്ചതെന്നും, ദൈവം തന്റെ കർതൃത്വത്തിൽ തന്റെ വീണ്ടെടുപ്പ് ലക്ഷ്യങ്ങൾക്കായി തിന്മയെപ്പോലും എങ്ങനെ ഉപയോഗിക്കുന്നുവെന്നും കണ്ടെത്തുക (ഉല്പത്തി 50:20, റോമർ 8:28). ദൈവത്തിന്റെ നന്മ, മനുഷ്യ സ്വതന്ത്ര ഇച്ഛാശക്തി, വീണ്ടെടുപ്പിനായി ഞരങ്ങുന്ന വീണുപോയ ലോകത്തിന്റെ യാഥാർത്ഥ്യം എന്നിവയ്ക്കിടയിലുള്ള ബൈബിൾ പിരിമുറുക്കം പര്യവേക്ഷണം ചെയ്യുക (റോമർ 8:18-25). ദൈവത്തിന്റെ വഴികൾ നമ്മുടെ ധാരണയ്ക്കപ്പുറമാണെങ്കിലും അവന്റെ സ്വഭാവത്തിൽ വിശ്വസിക്കാൻ പഠിക്കുക (യെശയ്യാവ് 55:8-9), നമ്മുടെ പേരിൽ ക്രിസ്തുവിന്റെ കഷ്ടപ്പാടിലൂടെ അവൻ തന്റെ സ്നേഹം പരമമായി പ്രദർശിപ്പിച്ചുവെന്ന് അറിയുന്നു (റോമർ 5:8).'
WHERE topic_id = 'AAA00000-e29b-41d4-a716-446655440002' AND language_code = 'ml';

-- AAA-007 ml: replace "പരമാധികാര", "ഹൈപ്പർ-കാൽവിനിസം", "സെമി-പെലാജിയാനിസം"
UPDATE recommended_topics_translations
SET description = 'ദൈവത്തിന്റെ കർതൃ മുൻനിർണയം (എഫെസ്യർ 1:4-5, റോമർ 8:29-30) വിശ്വസിക്കാനും മാനസാന്തരപ്പെടാനുമുള്ള മനുഷ്യ ഉത്തരവാദിത്വം (പ്രവൃത്തികൾ 17:30, യോഹന്നാൻ 3:16-18) എന്നിവയ്ക്കിടയിലുള്ള ബൈബിൾ പിരിമുറുക്കം നാവിഗേറ്റ് ചെയ്യുക. അവ എങ്ങനെ ഒരുമിച്ച് യോജിക്കുന്നുവെന്ന് വിശദീകരിക്കാതെ തന്നെ തിരുവെഴുത്ത് നിർഭയമായി രണ്ട് സത്യങ്ങളും സ്ഥിരീകരിക്കുന്നുവെന്ന് മനസ്സിലാക്കുക: ലോകസ്ഥാപനത്തിനു മുമ്പ് ദൈവം തന്റെ തിരഞ്ഞെടുക്കപ്പെട്ടവരെ തിരഞ്ഞെടുത്തു, എന്നാൽ സുവിശേഷത്തോടുള്ള അവരുടെ പ്രതികരണത്തിന് ആളുകൾ യഥാർത്ഥമായി ഉത്തരവാദികളാണ്. രക്ഷയിൽ ദൈവത്തിന്റെ കേവല കർതൃത്വത്തെക്കുറിച്ചുള്ള പരിഷ്കൃത ഊന്നലും മനുഷ്യ സ്വതന്ത്ര ഇച്ഛാശക്തിയെയും പ്രതിരോധിക്കാവുന്ന കൃപയെയും കുറിച്ചുള്ള ആർമിനിയൻ ഊന്നലും പര്യവേക്ഷണം ചെയ്യുക, ആത്മാർത്ഥരായ വിശ്വാസികൾ രണ്ട് വീക്ഷണങ്ങളും പുലർത്തുന്നുവെന്ന് തിരിച്ചറിയുന്നു. അതിരുകടന്ന പിശകുകൾ ഒഴിവാക്കുക - മനുഷ്യ ഉത്തരവാദിത്തം നിഷേധിക്കുന്ന ചിന്ത, അല്ലെങ്കിൽ ദൈവത്തിന്റെ കർതൃത്വം കുറയ്ക്കുന്ന ചിന്ത. ദൈവത്തിന്റെ നിഗൂഢമായ ജ്ഞാനത്തിൽ വിശ്രമിക്കുക (റോമർ 11:33-36), അതേസമയം അടിയന്തിരമായി എല്ലാവർക്കും സുവിശേഷം പ്രഖ്യാപിക്കുക, ദൈവം തന്റെ ലക്ഷ്യങ്ങൾ നിറവേറ്റാൻ മാനുഷിക മാർഗങ്ങൾ ഉപയോഗിക്കുന്നുവെന്ന് അറിയുന്നു (റോമർ 10:14-17).'
WHERE topic_id = 'AAA00000-e29b-41d4-a716-446655440007' AND language_code = 'ml';

-- 222-008 ml: replace "ആത്മനിഷ്ഠ" and "വസ്തുനിഷ്ഠ"
UPDATE recommended_topics_translations
SET description = 'മുതിർന്ന വിശ്വാസികളെപ്പോലും ബാധിക്കുന്ന സംശയത്തെയും ഭയത്തെയും അതിജീവിക്കുന്നതിനുള്ള ബൈബിൾപരമായ തന്ത്രങ്ങൾ പഠിക്കുക. മനസ്സിന്റെ വികാരങ്ങളെ ആശ്രയിക്കുന്നതിനുപകരം തിരുവെഴുത്തിന്റെ വ്യക്തവും ഉറപ്പുള്ള സത്യം കൊണ്ട് നിങ്ങളുടെ മനസ്സിനെ പൂരിതമാക്കി സംശയത്തെ പോരാടുക (സങ്കീർത്തനം 119:11, റോമർ 10:17), നിങ്ങളുടെ ജീവിതത്തിലും ചരിത്രത്തിലും ദൈവത്തിന്റെ മുൻകാല വിശ്വസ്തത ഓർത്തുകൊണ്ട് (സങ്കീർത്തനം 77:11-12), നിങ്ങളുടെ ചോദ്യങ്ങൾ സത്യസന്ധമായി ദൈവത്തിന്റെ അടുക്കൽ കൊണ്ടുവരുന്നതിലൂടെ, അവൻ ആത്മാർത്ഥരായ അന്വേഷകരെ സ്വാഗതം ചെയ്യുന്നു (മർക്കോസ് 9:24). ഭയത്തെ ഇല്ലാതാക്കുന്ന ദൈവത്തിന്റെ പൂർണ്ണ സ്നേഹത്തിൽ ധ്യാനിച്ചുകൊണ്ട് (1 യോഹന്നാൻ 4:18), എല്ലാ സാഹചര്യങ്ങളുടെയും മേൽ അവന്റെ കർതൃ നിയന്ത്രണം (മത്തായി 10:29-31), നിങ്ങളെ ഒരിക്കലും ഉപേക്ഷിക്കാനോ ഉപേക്ഷിക്കാനോ അവന്റെ വാഗ്ദാനങ്ങൾ (എബ്രായർ 13:5-6) എന്നിവയിലൂടെ ഭയത്തെ അതിജീവിക്കുക. ഉത്കണ്ഠാകുലമായ ചിന്തകളെ പ്രാർത്ഥനയും കൃതജ്ഞതയും കൊണ്ട് മാറ്റിസ്ഥാപിക്കുക, ദൈവത്തിന്റെ സമാധാനം നിങ്ങളുടെ ഹൃദയത്തെയും മനസ്സിനെയും സംരക്ഷിക്കട്ടെ (ഫിലിപ്പിയർ 4:6-7). വിശ്വാസം എന്നത് സംശയത്തിന്റെയോ ഭയത്തിന്റെയോ അഭാവമല്ല, മറിച്ച് അവയെ അവഗണിച്ചുകൊണ്ട് ദൈവത്തിൽ വിശ്വസിക്കുക, നിങ്ങളുടെ വികാരങ്ങൾക്കുമേലെ അവന്റെ വചനം വിശ്വസിക്കാൻ തിരഞ്ഞെടുക്കുക എന്നതാണ് എന്ന് ഓർക്കുക.'
WHERE topic_id = '222e8400-e29b-41d4-a716-446655440008' AND language_code = 'ml';

-- 444-006 ml: replace "വസ്തുനിഷ്ഠ" and "ആത്മനിഷ്ഠ"
UPDATE recommended_topics_translations
SET description = 'വിശ്വാസത്താൽ ജീവിക്കുന്നതും (ദൈവത്തിന്റെ വ്യക്തമായ സത്യത്തിൽ വിശ്വസിക്കുന്നത്) വികാരങ്ങളാൽ ജീവിക്കുന്നതും (മനസ്സിന്റെ വികാരങ്ങളിൽ വിശ്വസിക്കുന്നത്) തമ്മിലുള്ള നിർണായകമായ വ്യത്യാസം പഠിക്കുക. ബൈബിൾപരമായ വിശ്വാസം ഒരു യുക്തിരഹിതമായ കുതിപ്പോ ആശാവാദമോ അല്ല, മറിച്ച് തിരുവെഴുത്തിൽ വെളിപ്പെടുത്തിയിരിക്കുന്ന ദൈവത്തിന്റെ തെളിയിക്കപ്പെട്ട സ്വഭാവത്തിലും വാഗ്ദാനങ്ങളിലുമുള്ള ആത്മവിശ്വാസപൂർണ്ണമായ വിശ്വാസമാണെന്ന് മനസ്സിലാക്കുക (എബ്രായർ 11:1, റോമർ 10:17). വികാരങ്ങൾ യഥാർത്ഥമാണെന്നാൽ അവിശ്വാസ്യമായ വഴികാട്ടികളാണെന്ന് തിരിച്ചറിയുക - അവ സാഹചര്യങ്ങൾ, ഹോർമോണുകൾ, ഉറക്കം, എണ്ണമറ്റ മറ്റ് ഘടകങ്ങൾ എന്നിവയെ അടിസ്ഥാനമാക്കി ഏറ്റക്കുറച്ചിലുകൾ സംഭവിക്കുന്നു, അതേസമയം ദൈവവചനം എന്നേക്കും മാറ്റമില്ലാതെ നിലനിൽക്കുന്നു (യെശയ്യാവ് 40:8, മത്തായി 24:35). നിങ്ങൾക്ക് ദൈവസാന്നിധ്യം അനുഭവപ്പെടാത്തപ്പോൾ, പ്രാർത്ഥനകൾക്ക് ഉത്തരമില്ലെന്ന് തോന്നുമ്പോൾ, സാഹചര്യങ്ങൾ നിരാശാജനകമായി കാണപ്പെടുമ്പോൾ, അല്ലെങ്കിൽ സംശയങ്ങൾ നിങ്ങളുടെ മനസ്സിനെ ആക്രമിക്കുമ്പോൾ വിശ്വാസത്താൽ നടക്കാൻ പരിശീലിക്കുക (2 കൊരിന്ത്യർ 5:7, ഹബക്കൂക്ക് 3:17-19). തിരുവെഴുത്തിൽ ധ്യാനിച്ചുകൊണ്ട്, ദൈവത്തിന്റെ മുൻകാല വിശ്വസ്തത ഓർത്തുകൊണ്ട്, നിങ്ങൾക്ക് എങ്ങനെ തോന്നുന്നുവെന്ന് പരിഗണിക്കാതെ ദൈവം തന്നെക്കുറിച്ചും നിങ്ങളുടെ സ്വത്വത്തെക്കുറിച്ചും നിങ്ങളുടെ ഭാവിയെക്കുറിച്ചും പറയുന്നത് വിശ്വസിക്കാൻ ദിവസേന തിരഞ്ഞെടുക്കുന്നതിലൂടെ വിശ്വാസം വളർത്തുക. വൈകാരിക ഉയർച്ചകളേക്കാൾ സഹിഷ്ണുതയുള്ള വിശ്വാസം ദൈവത്തെ വളരെയധികം ബഹുമാനിക്കുന്നുവെന്നും, അവനെ ആത്മാർത്ഥമായി അന്വേഷിക്കുന്നവരെ അവൻ പ്രതിഫലം നൽകുന്നുവെന്നും വിശ്വസിക്കുക (എബ്രായർ 11:6).'
